error_message:
Resource provider operation failed: An error occurred (InvalidDefinition) when calling the CreateStateMachine operation: Error=RecognitionException Args=["Unknown service 'rekognition'"] in definition '{
  "StartAt": "ValidateImage",
  "States": {
    "ValidateImage": {
      "Type": "Task",
      "Resource": "arn:aws:states:::lambda:invoke",
      "Parameters": {
        "FunctionName": "arn:aws:lambda:FUNCTION_REGION:ACCOUNT_ID:function:ValidateImageLambda",
        "Payload": {
          "bucket.$": "$.bucket",
          "key.$": "$.key"
        }
      },
      "Next": "DetectLabels"
    },
    "DetectLabels": {
      "Type": "Task",
      "Resource": "arn:aws:states:::rekognition:detectLabels",
      "Parameters": {
        "Image": {
          "S3Object": {
            "Bucket.$": "$.bucket",
            "Name.$": "$.key"
          }
        },
        "MaxLabels": 10,
        "MinConfidence": 75
      },
      "Next": "CheckForHuman"
    },
    "CheckForHuman": {
      "Type": "Choice",
      "Choices": [
        {
          "Variable": "$.Labels",
          "StringEquals": "Human",
          "Next": "SendAlert"
        },
        {
          "Variable": "$.Labels",
          "StringEquals": "Person",
          "Next": "SendAlert"
        }
      ],
      "Default": "End"
    },
    "SendAlert": {
      "Type": "Task",
      "Resource": "arn:aws:states:::sns:publish",
      "Parameters": {
        "TopicArn": "arn:aws:sns:REGION:ACCOUNT_ID:ImageRecognitionAlerts",
        "Message": "Human detected in image: ${$.key}"
      },
      "End": true
    },
    "End": {
      "Type": "Pass",
      "End": true
    }
  }
}
